from kelvin.api.client import Client

    # Login
    client = Client(url="https://<url.kelvin.ai>", username="<your_username>")
    client.login(password="<your_password>")

    # Create Scheduled Parameter Change and Revert
    response = client.parameters.create_parameters_schedule(data={
        "app_name": "pcp-optimization",
        "app_version": "1.0.05221921",
        "scheduled_for": "2025-06-14T08:00:00Z",
        "comment": "Threshold change for updated maintenance period.",
        "resources": [
            "krn:asset:pcp_01",
            "krn:asset:pcp_02"
        ],
        "parameters": {
            "dd_rate_max": 0.55,
            "dd_rate_min": 0.12
        },
        "revert": {
            "scheduled_for": "2025-06-16T18:00:00Z",
            "resource_parameters": [
                {
                    "resource": "krn:asset:pcp_01",
                    "parameters": {
                        "dd_rate_max": 0.5,
                        "dd_rate_min": 0.1
                    }
                },
                {
                    "resource": "krn:asset:pcp_02",
                    "parameters": {
                        "dd_rate_max": 0.5,
                        "dd_rate_min": 0.1
                    }
                }
            ]
        }
    })

    print(response)

